double avg_per_group(const std::vector<std::string>& keys, const std::vector<int>& vals, const std::string& q){
    std::map<std::string,int> sum;
    std::map<std::string,int> cnt;
    for (size_t i = 0; i < keys.size(); ++i){ sum[keys[i]] += vals[i]; cnt[keys[i]] += 1; }
    if (cnt.find(q) == cnt.end()) return 0.0;
    return (double)sum[q] / (double)cnt[q];
}

