int window_distinct(const std::vector<int>& a, int w, int start){
    std::map<int,int> cnt;
    for (int i = start; i < start + w && i < (int)a.size(); ++i) cnt[a[i]] += 1;
    int distinct = 0;
    for (int i = start; i < start + w && i < (int)a.size(); ++i){
        if (cnt[a[i]] > 0){ distinct += 1; cnt[a[i]] = 0; }
    }
    return distinct;
}

