int lru_evict(const std::vector<int>& accesses, int cap, int query){
    std::map<int,int> present;
    std::vector<int> order;
    for (size_t i = 0; i < accesses.size(); ++i){
        int k = accesses[i];
        if (present.find(k) != present.end()){
            for (size_t j = 0; j < order.size(); ++j){ if (order[j] == k){ order.erase(order.begin()+j); break; } }
            order.push_back(k);
        } else {
            if ((int)order.size() >= cap){
                int victim = order.front();
                order.erase(order.begin());
                present.erase(victim);
            }
            present[k] = 1;
            order.push_back(k);
        }
    }
    return present.find(query) != present.end() ? 1 : 0;
}

mojo_unit:
def lru_evict(accesses: List[Int], cap: Int, query: Int) raises -> Int:
    var present = Dict[Int, Int]()
    var order = List[Int]()
    for i in range(len(accesses)):
        var k = accesses[i]
        if k in present:
            for j in range(len(order)):
                if order[j] == k:
                    _ = order.pop(j)
                    break
            order.append(k)
        else:
            if len(order) >= cap:
                var victim = order[0]
                _ = order.pop(0)
                _ = present.pop(victim)
            present[k] = 1
            order.append(k)
    if query in present:
        return 1
    return 0

