long fib_helper(int n, std::map<int,long>& memo){
    if (n < 2) return n;
    if (memo.find(n) != memo.end()) return memo[n];
    long r = fib_helper(n-1, memo) + fib_helper(n-2, memo);
    memo[n] = r;
    return r;
}
long fib_memo(int n){
    std::map<int,long> memo;
    return fib_helper(n, memo);
}

