    var run = 0
    pre[0] = 0
    for i in range(len(a)):
        run += a[i]
        pre[i + 1] = run
    var left = 0
    if lo in pre:
        left = pre[lo]
    var right = 0
    if hi in pre:
        right = pre[hi]
    return right - left

